import Foundation

enum APIEnvironment {
    case development, staging, production

    var baseURL: URL {
        switch self {
        case .development: return URL(string: "https://api-development.example.com")!
        case .staging: return URL(string: "https://api-staging.example.com")!
        case .production: return URL(string: "https://api.example.com")!
        }
    }
}

struct APIClient {
    private let session: URLSession
    private let baseURL = APIEnvironment.development.baseURL

    init() {
        self.session = URLSession.shared
    }

    func get<T: Decodable>(from endpoint: String, completionHandler: @escaping (Result<T, Error>) -> Void) {
        let url = baseURL.appendingPathComponent(endpoint)
        var request = URLRequest(url: url)
        request.httpMethod = "GET"

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completionHandler(.failure(error))
                return
            }

            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completionHandler(.failure(NSError(domain: "APIClient", code: -1, userInfo: nil)))
                return
            }

            guard let data = data else {
                completionHandler(.failure(NSError(domain: "APIClient", code: -2, userInfo: nil)))
                return
            }

            do {
                let decodedResponse = try JSONDecoder().decode(T.self, from: data)
                completionHandler(.success(decodedResponse))
            } catch {
                completionHandler(.failure(error))
            }
        }

        task.resume()
    }

    func post<T: Encodable>(to endpoint: String, data: T, completionHandler: @escaping (Result<Void, Error>) -> Void) {
        let url = baseURL.appendingPathComponent(endpoint)
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")

        let jsonData = try? JSONEncoder().encode(data)

        guard let httpBody = jsonData else {
            completionHandler(.failure(NSError(domain: "APIClient", code: -3, userInfo: nil)))
            return
        }

        request.httpBody = httpBody

        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completionHandler(.failure(error))
                return
            }

            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completionHandler(.failure(NSError(domain: "APIClient", code: -4, userInfo: nil)))
                return
            }

            completionHandler(.success(()))
        }

        task.resume()
    }
}